# Label registry file
LABEL_REGISTRY_PATH = os.path.join(DATA_FOLDER, 'label_registry.json')


def allowed_file(filename, allowed_exts=None):
    if allowed_exts is None:
        allowed_exts = ALLOWED_EXTENSIONS
    return '.' in filename and filename.rsplit('.', 1)[1].lower() in allowed_exts


def load_label_registry():
    if os.path.exists(LABEL_REGISTRY_PATH):
        with open(LABEL_REGISTRY_PATH, 'r') as f:
            return json.load(f)
    return {'labels': {}, 'class_names': []}


def save_label_registry(registry):
    with open(LABEL_REGISTRY_PATH, 'w') as f:
        json.dump(registry, f, indent=2)


def sanitize_input(text):
    """Basic input sanitization to prevent injection attacks."""
    if not isinstance(text, str):
        return str(text)
    # Remove potentially dangerous characters
    sanitized = text.strip()
    sanitized = sanitized.replace('..', '')
    sanitized = sanitized.replace('/', '')
    sanitized = sanitized.replace('\\', '')
    # Limit length
    return sanitized[:256]


def validate_image(image_bytes):
    """Validate that uploaded bytes are actually a valid image."""
    try:
        img = Image.open(io.BytesIO(image_bytes))
        img.verify()
        # Re-open after verify
        img = Image.open(io.BytesIO(image_bytes))
        if img.size[0] < 1 or img.size[1] < 1:
            return False, "Image dimensions too small"
        if img.size[0] > 10000 or img.size[1] > 10000:
            return False, "Image dimensions too large"
        return True, "Valid"
    except Exception as e:
        return False, f"Invalid image: {str(e)}"


def preprocess_image(image_path):
    """Load and preprocess a single image."""
    try:
        img = tf.io.read_file(image_path)
        img = tf.image.decode_image(img, channels=3, expand_animations=False)
        img = tf.image.resize(img, IMAGE_SIZE)
        img = tf.cast(img, tf.float32) / 255.0
        return img
    except Exception as e:
        logger.error(f"Error preprocessing image {image_path}: {e}")
        return None


def preprocess_image_from_bytes(image_bytes):
    """Preprocess image from bytes."""
    try:
        img = Image.open(io.BytesIO(image_bytes)).convert('RGB')
        img = img.resize(IMAGE_SIZE)
        img_array = np.array(img, dtype=np.float32) / 255.0
        return img_array
    except Exception as e:
        logger.error(f"Error preprocessing image bytes: {e}")
        return None


def build_model(num_classes):
    """Build a CNN model for image classification."""
    model = keras.Sequential([
        layers.Input(shape=(IMAGE_SIZE[0], IMAGE_SIZE[1], 3)),

        # Data augmentation layers
        layers.RandomFlip("horizontal"),
        layers.RandomRotation(0.1),
        layers.RandomZoom(0.1),

        # Conv Block 1
        layers.Conv2D(32, (3, 3), activation='relu', padding='same'),
        layers.BatchNormalization(),
        layers.Conv2D(32, (3, 3), activation='relu', padding='same'),
        layers.BatchNormalization(),
        layers.MaxPooling2D((2, 2)),
        layers.Dropout(0.25),

        # Conv Block 2
        layers.Conv2D(64, (3, 3), activation='relu', padding='same'),
        layers.BatchNormalization(),
        layers.Conv2D(64, (3, 3), activation='relu', padding='same'),
        layers.BatchNormalization(),
        layers.MaxPooling2D((2, 2)),
        layers.Dropout(0.25),

        # Conv Block 3
        layers.Conv2D(128, (3, 3), activation='relu', padding='same'),
        layers.BatchNormalization(),
        layers.Conv2D(128, (3, 3), activation='relu', padding='same'),
        layers.BatchNormalization(),
        layers.MaxPooling2D((2, 2)),
        layers.Dropout(0.25),

        # Dense layers
        layers.Flatten(),
        layers.Dense(256, activation='relu'),
        layers.BatchNormalization(),
        layers.Dropout(0.5),
        layers.Dense(128, activation='relu'),
        layers.BatchNormalization(),
        layers.Dropout(0.5),
        layers.Dense(num_classes, activation='softmax')
    ])

    model.compile(
        optimizer=keras.optimizers.Adam(learning_rate=0.001),
        loss='sparse_categorical_crossentropy',
        metrics=['accuracy']
    )

    return model


def load_training_data():
    """Load all training data from the data folder."""
    registry = load_label_registry()
    images = []
    labels = []

    for image_id, info in registry['labels'].items():
        image_path = os.path.join(DATA_FOLDER, 'images', f"{image_id}.png")
        if os.path.exists(image_path):
            img = preprocess_image(image_path)
            if img is not None:
                images.append(img.numpy())
                labels.append(info['class_index'])

    if not images:
        return None, None, []

    return np.array(images), np.array(labels), registry['class_names']


def load_csv_training_data(csv_path):
    """
    Load training data from CSV file.
    Expected CSV format:
    - 'image_path': path to image file (relative or absolute)
    - 'label': class label string
    OR
    - pixel columns (flattened image data) with 'label' column
    """
    try:
        df = pd.read_csv(csv_path)

        if df.empty:
            return None, None, [], "CSV file is empty"

        if 'label' not in df.columns:
            return None, None, [], "CSV must contain a 'label' column"

        # Sanitize labels
        df['label'] = df['label'].apply(sanitize_input)

        registry = load_label_registry()
        class_names = registry['class_names']

        images = []
        labels = []

        if 'image_path' in df.columns:
            # CSV references image files
            for _, row in df.iterrows():
                img_path = row['image_path']
                label = row['label']

                if label not in class_names:
                    class_names.append(label)

                class_index = class_names.index(label)

                if os.path.exists(img_path):
                    img = preprocess_image(img_path)
                    if img is not None:
                        # Save to our data folder
                        image_id = str(uuid.uuid4())
                        save_path = os.path.join(DATA_FOLDER, 'images', f"{image_id}.png")
                        os.makedirs(os.path.dirname(save_path), exist_ok=True)

                        pil_img = Image.fromarray((img.numpy() * 255).astype(np.uint8))
                        pil_img.save(save_path)

                        registry['labels'][image_id] = {
                            'class_index': class_index,
                            'class_name': label,
                            'source': 'csv_upload',
                            'timestamp': datetime.now().isoformat()
                        }

                        images.append(img.numpy())
                        labels.append(class_index)
        else:
            # CSV contains pixel data
            pixel_columns = [col for col in df.columns if col != 'label']

            if not pixel_columns:
                return None, None, [], "No pixel data or image_path column found"

            num_pixels = len(pixel_columns)
            side = int(np.sqrt(num_pixels / 3)) if num_pixels > 1000 else int(np.sqrt(num_pixels))

            for _, row in df.iterrows():
                label = row['label']

                if label not in class_names:
                    class_names.append(label)

                class_index = class_names.index(label)

                try:
                    pixels = row[pixel_columns].values.astype(np.float32)

                    if num_pixels == side * side * 3:
                        img = pixels.reshape(side, side, 3)
                    elif num_pixels == side * side:
                        img = pixels.reshape(side, side, 1)
                        img = np.repeat(img, 3, axis=2)
                    else:
                        continue

                    if img.max() > 1.0:
                        img = img / 255.0

                    img_resized = tf.image.resize(img, IMAGE_SIZE).numpy()

                    # Save to data folder
                    image_id = str(uuid.uuid4())
                    save_path = os.path.join(DATA_FOLDER, 'images', f"{image_id}.png")
                    os.makedirs(os.path.dirname(save_path), exist_ok=True)

                    pil_img = Image.fromarray((img_resized * 255).astype(np.uint8))
                    pil_img.save(save_path)

                    registry['labels'][image_id] = {
                        'class_index': class_index,
                        'class_name': label,
                        'source': 'csv_pixel_upload',
                        'timestamp': datetime.now().isoformat()
                    }

                    images.append(img_resized)
                    labels.append(class_index)
                except Exception as e:
                    logger.warning(f"Skipping row due to error: {e}")
                    continue

        registry['class_names'] = class_names
        save_label_registry(registry)

        if not images:
            return None, None, class_names, "No valid images found in CSV"

        return np.array(images), np.array(labels), class_names, None

    except Exception as e:
        return None, None, [], f"Error loading CSV: {str(e)}"


def train_model_async():
    """Train the model in a background thread."""
    global is_training, model_metadata

    try:
        is_training = True
        logger.info("Starting model training...")

        images, labels, class_names = load_training_data()

        if images is None or len(images) < 2:
            logger.warning("Not enough training data. Need at least 2 samples.")
            is_training = False
            return

        num_classes = len(class_names)

        if num_classes < 2:
            logger.warning("Need at least 2 classes to train.")
            is_training = False
            return

        # Split data into train and validation
        num_samples = len(images)
        indices = np.random.permutation(num_samples)
        split = max(1, int(0.8 * num_samples))

        train_images = images[indices[:split]]
        train_labels = labels[indices[:split]]
        val_images = images[indices[split:]]
        val_labels = labels[indices[split:]]

        with model_lock:
            model = build_model(num_classes)

            # Check if previous model exists and has same num_classes
            model_path = os.path.join(MODEL_FOLDER, 'latest_model.keras')
            if os.path.exists(model_path) and model_metadata['num_classes'] == num_classes:
                try:
                    model = keras.models.load_model(model_path)
                    logger.info("Loaded existing model for fine-tuning")
                except Exception:
                    logger.info("Building new model")
                    model = build_model(num_classes)

            callbacks = [
                keras.callbacks.EarlyStopping(
                    monitor='val_loss' if len(val_images) > 0 else 'loss',
                    patience=3,
                    restore_best_weights=True
                ),
                keras.callbacks.ReduceLROnPlateau(
                    monitor='val_loss' if len(val_images) > 0 else 'loss',
                    factor=0.5,
                    patience=2
                )
            ]

            validation_data = None
            if len(val_images) > 0:
                validation_data = (val_images, val_labels)

            history = model.fit(
                train_images, train_labels,
                batch_size=min(BATCH_SIZE, len(train_images)),
                epochs=EPOCHS,
                validation_data=validation_data,
                callbacks=callbacks,
                verbose=1
            )

            model.save(os.path.join(MODEL_FOLDER, 'latest_model.keras'))

            # Update metadata
            model_metadata['version'] += 1
            model_metadata['num_classes'] = num_classes
            model_metadata['class_names'] = class_names
            model_metadata['total_samples'] = num_samples
            model_metadata['last_trained'] = datetime.now().isoformat()

            if validation_data and 'val_accuracy' in history.history:
                model_metadata['accuracy'] = float(history.history['val_accuracy'][-1])
            elif 'accuracy' in history.history:
                model_metadata['accuracy'] = float(history.history['accuracy'][-1])

            # Save metadata
            with open(os.path.join(MODEL_FOLDER, 'metadata.json'), 'w') as f:
                meta_to_save = {k: v if not isinstance(v, set) else list(v)
                                for k, v in model_metadata.items()}
                json.dump(meta_to_save, f, indent=2)

        logger.info(f"Training complete. Model v{model_metadata['version']}, "
                     f"Accuracy: {model_metadata['accuracy']}")

    except Exception as e:
        logger.error(f"Training error: {e}")
    finally:
        is_training = False


